import sys
from kafka.admin import KafkaAdminClient, NewTopic

def create_topics(admin_client, topic_list, num_partitions, replication_factor, config):
    new_topics = [
        NewTopic(name=topic, num_partitions=num_partitions, replication_factor=replication_factor, topic_configs=config)
        for topic in topic_list
    ]
    admin_client.create_topics(new_topics=new_topics, validate_only=False)

def process_args(args):
    topic_names = args[args.index('--topics') + 1].split(',')
    num_partitions = int(args[args.index('--partitions') + 1])
    replication_factor = int(args[args.index('--replication-factor') + 1])
    config = dict(pair.split('=') for pair in args[args.index('--config') + 1].split(','))
    return topic_names, num_partitions, replication_factor, config

def main():
    if '--topics' not in sys.argv or '--partitions' not in sys.argv or '--replication-factor' not in sys.argv or '--config' not in sys.argv:
        print("Usage: script.py --topics <topic1,topic2> --partitions <num_partitions> --replication-factor <factor> --config <key1=val1,key2=val2>")
        sys.exit(1)
    
    topic_names, num_partitions, replication_factor, config = process_args(sys.argv)

    admin_client = KafkaAdminClient(bootstrap_servers='localhost:9092', client_id='admin-client')

    create_topics(admin_client, topic_names, num_partitions, replication_factor, config)
    admin_client.close()

if __name__ == '__main__':
    main()